<template>
  <!-- 顶部长图 -->
  <el-image v-if="headerImage" :src="headerImage" @click="openBrowser(versionHistoryUrl)" style="height: 17vh; cursor: pointer; width: 100%" />
</template>
<script>
import { getMultiConfig } from '@/api/main';
export default {
  name: 'MainHeaderImg',
  data() {
    return {
      headerImage: null,
      versionHistoryUrl: null
    };
  },
  method: {
    getConfig() {
      let params = {
        codeList: ['sys.main.header', 'sys.versionHistoryUrl']
      };
      // 获取配置信息
      getMultiConfig(params).then((multiConfig) => {
        this.headerImage = multiConfig.data['sys.main.header'] || '';
        this.versionHistoryUrl = multiConfig.data['sys.versionHistoryUrl'];
      });
    }
  }
};
</script>
